const now = new Date();
const posts = Array.isArray($input.first().json) ? $input.first().json : [];
return posts
  .filter(p => p && p.scheduled_at && new Date(p.scheduled_at) <= now)
  .map(p => {
    const hashtags = Array.isArray(p.hashtags) ? p.hashtags.join(' ') : (p.hashtags || '');
    const cta = p.cta || '';
    const emoji = { linkedin: '💼', twitter: '🐦', instagram: '📸', youtube: '🎬', email: '📧' }[p.platform] || '📱';
    const platform = (p.platform || '').charAt(0).toUpperCase() + (p.platform || '').slice(1);
    const time = new Date(p.scheduled_at).toLocaleString('en-PK', { timeZone: 'Asia/Karachi', dateStyle: 'long', timeStyle: 'short' });
    const subject = `${emoji} ${platform} Post Ready — ${time} PKT`;
    const imageBlock = p.preview_url
      ? `<img src="${p.preview_url}" style="width:100%;max-width:600px;border-radius:10px;margin:16px 0;display:block" alt="Visual" />`
      : '';
    const hashtagHtml = hashtags
      ? `<p style="color:#0077b5;font-size:14px;margin:8px 0">${hashtags}</p>`
      : '';
    const ctaHtml = cta
      ? `<p style="margin:12px 0"><strong>👉 ${cta}</strong></p>`
      : '';
    const html = `<!DOCTYPE html><html><body style="font-family:sans-serif;background:#f9f9f9;padding:24px">
<div style="max-width:600px;margin:0 auto;background:#fff;border-radius:12px;padding:24px;box-shadow:0 2px 8px rgba(0,0,0,.08)">
  <h2 style="margin:0 0 4px">${emoji} ${platform} Post Ready</h2>
  <p style="color:#888;font-size:13px;margin:0 0 16px">📅 ${time} PKT</p>
  ${imageBlock}
  <div style="background:#f4f4f4;padding:16px;border-radius:8px;margin:8px 0">
    <p style="white-space:pre-wrap;margin:0 0 12px">${(p.caption || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</p>
    ${hashtagHtml}
    ${ctaHtml}
  </div>
  <p style="color:#bbb;font-size:11px;margin:16px 0 0">Post ID: ${p.postiz_id}</p>
</div>
</body></html>`;
    return { json: { ...p, subject, html } };
  });
